public class ListNode {
    int val;
    ListNode next;
    ListNode(int x) { val = x; }
}

public ListNode plusOne(ListNode head) {
    if (head == null) return head;
    int carry = plusOneDfs(head);
    if (carry == 1) {
        ListNode newHead = new ListNode(1);
        newHead.next = head;
        return newHead;
    }
    return head;
}

